import { useEffect, useMemo, useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { supabase } from '@/lib/supabase'
import { useAuthStore } from '@/store/useAuthStore'
import { useFilterStore } from '@/store/useFilterStore'
import { applySm2, INITIAL_SRS, RATING_TO_QUALITY, RATING_XP, type Rating, type SrsState } from '@/lib/srs'
import { awardXp } from '@/lib/xp'
import { Header } from '@/components/Header'
import { Flashcard, type FlashcardData } from '@/components/Flashcard'
import { XPToast, type XpToastData } from '@/components/XPToast'

// Flashcards / SRS laut CLAUDE.md §6.1.
//
// Session-Logik:
//   1. Bei Mount: lade alle vocab_medical (gefiltert nach useFilterStore) +
//      alle srs_medical für den User. Mische clientside zu einer Session aus
//      ≤15 due Cards + Rest neu, max 20 total.
//   2. Render aktuelle Karte. Klick → Flip → 4 Buttons sichtbar.
//   3. Bewertung → optimistisches UI-Update (next Card sofort), gleichzeitig:
//        - SRS-Row upsert (insert wenn neu, update wenn existing)
//        - xp_event insert + profiles.app_xp.virag bumpen via awardXp()
//      Beides feuert "fire-and-forget" — Fehler logge ich, Game-Loop hält nicht an.
//   4. Wenn Session leer → Empty-State mit "fertig"-Anzeige + Link zurück.

type SrsRow = {
  id: number
  card_id: number
  ease_factor: number
  interval_days: number
  repetitions: number
  next_review_at: string
}

type SessionItem = {
  card: FlashcardData & { category: string; word_class: string | null; difficulty_base: number | null }
  srs: SrsRow | null
}

const PAGE_LIMIT = 20
const NEW_LIMIT = 5

const CATEGORY_LABELS: Record<string, string> = {
  all: 'Alle Themen',
  anamnese: 'Anamnese',
  anatomie: 'Anatomie',
  symptome: 'Symptome',
  krankheiten: 'Krankheiten',
  pharma: 'Pharma',
  untersuchung: 'Untersuchung',
  gynaekologie: 'Gynäkologie',
  verb: 'Verben',
  adjektiv: 'Adjektive',
  phrase: 'Phrasen'
}

export default function Flashcards() {
  const { user } = useAuthStore()
  const filter = useFilterStore()
  const navigate = useNavigate()

  const [session, setSession] = useState<SessionItem[] | null>(null)
  const [index, setIndex] = useState(0)
  const [flipped, setFlipped] = useState(false)
  const [toast, setToast] = useState<XpToastData | null>(null)
  const [reviewedCount, setReviewedCount] = useState(0)
  const [error, setError] = useState<string | null>(null)

  // Lade Session
  useEffect(() => {
    if (!user) return
    let cancelled = false

    async function load() {
      setSession(null)
      setError(null)

      // Vocab-Query mit Filter
      let q = supabase.from('vocab_medical').select(
        'id, hungarian, phonetic, german, latin_term, example_hu, example_de, category, word_class, difficulty_base'
      )
      if (filter.category !== 'all') q = q.eq('category', filter.category)
      if (filter.wordClass !== 'all') {
        // wordClass im Schema heißt 'noun'/'verb'/'adj'/... — UI-Mapping:
        const dbVal = filter.wordClass === 'adjective' ? 'adj' : filter.wordClass
        q = q.eq('word_class', dbVal)
      }
      if (filter.difficulty === 'easy') q = q.lte('difficulty_base', 2)
      if (filter.difficulty === 'medium') q = q.eq('difficulty_base', 3)
      if (filter.difficulty === 'hard') q = q.gte('difficulty_base', 4)

      const [cardsRes, srsRes] = await Promise.all([
        q,
        supabase
          .from('srs_medical')
          .select('id, card_id, ease_factor, interval_days, repetitions, next_review_at, production_mastered_at')
          .eq('user_id', user!.id)
      ])

      if (cancelled) return

      if (cardsRes.error) {
        setError(cardsRes.error.message)
        return
      }

      const srsByCardId = new Map<number, SrsRow & { production_mastered_at: string | null }>()
      for (const row of (srsRes.data ?? []) as Array<SrsRow & { production_mastered_at: string | null }>) {
        srsByCardId.set(row.card_id, row)
      }

      const now = Date.now()
      const cards = (cardsRes.data ?? []) as SessionItem['card'][]

      // Mastery-Filter clientseitig anwenden (DB hätte LEFT JOIN gebraucht)
      const matchesMastery = (s: typeof srsByCardId extends Map<number, infer V> ? V | undefined : never) => {
        switch (filter.mastery) {
          case 'unmastered': return !s || s.production_mastered_at === null
          case 'mastered': return !!s && s.repetitions >= 3
          case 'production_mastered': return !!s && s.production_mastered_at !== null
          default: return true
        }
      }

      const due: SessionItem[] = []
      const fresh: SessionItem[] = []

      for (const card of cards) {
        const s = srsByCardId.get(card.id)
        if (!matchesMastery(s)) continue
        if (!s) {
          fresh.push({ card, srs: null })
        } else if (new Date(s.next_review_at).getTime() <= now) {
          due.push({
            card,
            srs: {
              id: s.id,
              card_id: s.card_id,
              ease_factor: Number(s.ease_factor),
              interval_days: Number(s.interval_days),
              repetitions: s.repetitions,
              next_review_at: s.next_review_at
            }
          })
        }
      }

      // Random-shuffle innerhalb beider Pools für Abwechslung
      shuffle(due)
      shuffle(fresh)

      const dueSlice = due.slice(0, PAGE_LIMIT - Math.min(NEW_LIMIT, fresh.length))
      const freshSlice = fresh.slice(0, Math.max(NEW_LIMIT, PAGE_LIMIT - dueSlice.length))
      const combined = [...dueSlice, ...freshSlice].slice(0, PAGE_LIMIT)

      setSession(combined)
      setIndex(0)
      setFlipped(false)
      setReviewedCount(0)
    }

    void load()
    return () => { cancelled = true }
  }, [user, filter.category, filter.wordClass, filter.difficulty, filter.mastery])

  const current = session?.[index] ?? null
  const remaining = session ? session.length - index : 0

  async function handleRate(rating: Rating) {
    if (!current || !user) return

    const quality = RATING_TO_QUALITY[rating]
    const baseSrs: SrsState = current.srs
      ? {
          ease_factor: current.srs.ease_factor,
          interval_days: current.srs.interval_days,
          repetitions: current.srs.repetitions
        }
      : INITIAL_SRS

    const next = applySm2(baseSrs, quality)
    const isCorrect = quality >= 3

    // Optimistisch: nächste Karte sofort
    const reviewedCard = current
    setIndex((i) => i + 1)
    setFlipped(false)
    setReviewedCount((c) => c + 1)

    // Async Persistierung — fire and forget. Bei UPDATE: read-modify-write
    // für total_reviews / correct_reviews (im MVP tolerable Race-Conditions).
    void (async () => {
      try {
        const srsBase = {
          ease_factor: next.ease_factor,
          interval_days: next.interval_days,
          repetitions: next.repetitions,
          next_review_at: next.next_review_at,
          last_reviewed_at: new Date().toISOString()
        }

        if (reviewedCard.srs) {
          const { data: cur } = await supabase
            .from('srs_medical')
            .select('total_reviews, correct_reviews')
            .eq('id', reviewedCard.srs.id)
            .single()
          const total = ((cur as { total_reviews: number } | null)?.total_reviews ?? 0) + 1
          const correct =
            ((cur as { correct_reviews: number } | null)?.correct_reviews ?? 0) + (isCorrect ? 1 : 0)
          await supabase
            .from('srs_medical')
            .update({ ...srsBase, total_reviews: total, correct_reviews: correct })
            .eq('id', reviewedCard.srs.id)
        } else {
          await supabase.from('srs_medical').insert({
            user_id: user.id,
            card_id: reviewedCard.card.id,
            ...srsBase,
            total_reviews: 1,
            correct_reviews: isCorrect ? 1 : 0
          })
        }

        const result = await awardXp({
          baseAmount: RATING_XP[rating],
          source: `flashcard_${rating}`,
          mode: 'medical'
        })
        if (result) {
          setToast({ id: Date.now(), ...result })
        }
      } catch (err) {
        console.error('SRS persist failed:', err)
      }
    })()
  }

  // Toast-Auto-Dismiss
  useEffect(() => {
    if (!toast) return
    const t = setTimeout(() => setToast(null), 1200)
    return () => clearTimeout(t)
  }, [toast])

  const filterLabel = useMemo(() => {
    const cat = CATEGORY_LABELS[filter.category] ?? filter.category
    return cat
  }, [filter.category])

  // Render-Pfade
  if (session === null) {
    return (
      <Wrapper>
        <Status>Karten werden geladen…</Status>
      </Wrapper>
    )
  }

  if (error) {
    return (
      <Wrapper>
        <Status>⚠ Fehler: {error}</Status>
      </Wrapper>
    )
  }

  if (!current) {
    return (
      <Wrapper>
        <div style={{ textAlign: 'center', display: 'flex', flexDirection: 'column', gap: 12, alignItems: 'center' }}>
          <div style={{ fontSize: '4rem' }}>🌺</div>
          <h2 className="app-name" style={{ color: 'var(--green)', margin: 0, fontSize: '1.4rem' }}>
            {reviewedCount > 0 ? 'Geschafft!' : 'Keine fälligen Karten'}
          </h2>
          <p style={{ opacity: 0.7, maxWidth: 320 }}>
            {reviewedCount > 0
              ? `Du hast ${reviewedCount} ${reviewedCount === 1 ? 'Karte' : 'Karten'} gelernt. Komm später wieder — die nächsten sind später heute oder morgen fällig.`
              : 'Hier wartet gerade nichts auf dich. Andere Filter oder Kategorie probieren?'}
          </p>
          <button
            onClick={() => navigate('/home')}
            style={{
              marginTop: '1rem',
              background: 'var(--red)',
              color: 'var(--cream)',
              border: 'none',
              padding: '0.7rem 1.4rem',
              borderRadius: 10,
              fontWeight: 700,
              fontSize: '0.95rem',
              fontFamily: 'inherit',
              cursor: 'pointer'
            }}
          >
            Zurück zu Home
          </button>
        </div>
      </Wrapper>
    )
  }

  return (
    <Wrapper>
      {/* Top-Bar: Progress + Filter-Hinweis */}
      <div
        style={{
          width: '100%',
          maxWidth: 380,
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'center',
          fontSize: '0.8rem',
          opacity: 0.65,
          marginBottom: '0.5rem'
        }}
      >
        <span>{filterLabel}</span>
        <span>{remaining} {remaining === 1 ? 'Karte' : 'Karten'}</span>
      </div>

      <Flashcard card={current.card} flipped={flipped} onFlip={() => setFlipped((f) => !f)} />

      {/* Bewertungsbuttons — nur sichtbar nach Flip */}
      <div
        style={{
          width: '100%',
          maxWidth: 380,
          marginTop: '1.2rem',
          display: 'grid',
          gridTemplateColumns: 'repeat(4, 1fr)',
          gap: 6,
          opacity: flipped ? 1 : 0,
          pointerEvents: flipped ? 'auto' : 'none',
          transition: 'opacity 200ms'
        }}
      >
        <RateButton color="var(--red)" label="Again" sublabel="2 XP" onClick={() => handleRate('again')} />
        <RateButton color="var(--orange)" label="Hard" sublabel="5 XP" onClick={() => handleRate('hard')} />
        <RateButton color="var(--lg)" label="Good" sublabel="10 XP" onClick={() => handleRate('good')} />
        <RateButton color="var(--green)" label="Easy" sublabel="15 XP" onClick={() => handleRate('easy')} />
      </div>

      <button
        onClick={() => navigate('/home')}
        style={{
          marginTop: '1.5rem',
          background: 'none',
          border: '1.5px solid rgba(0,0,0,0.15)',
          padding: '0.4rem 0.9rem',
          borderRadius: 8,
          fontFamily: 'inherit',
          fontSize: '0.8rem',
          cursor: 'pointer',
          opacity: 0.65
        }}
      >
        Sitzung abbrechen
      </button>

      <XPToast toast={toast} />
    </Wrapper>
  )
}

function Wrapper({ children }: { children: React.ReactNode }) {
  return (
    <div style={{ minHeight: '100vh', display: 'flex', flexDirection: 'column', background: 'var(--cream)' }}>
      <Header />
      <main
        style={{
          flex: 1,
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          padding: '1.5rem 1rem 3rem'
        }}
      >
        {children}
      </main>
    </div>
  )
}

function Status({ children }: { children: React.ReactNode }) {
  return <div style={{ opacity: 0.5, fontSize: '0.95rem' }}>{children}</div>
}

function RateButton({
  color,
  label,
  sublabel,
  onClick
}: {
  color: string
  label: string
  sublabel: string
  onClick: () => void
}) {
  return (
    <button
      onClick={onClick}
      style={{
        background: color,
        color: 'var(--cream)',
        border: 'none',
        padding: '0.6rem 0.3rem',
        borderRadius: 10,
        fontFamily: 'inherit',
        cursor: 'pointer',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        gap: 2
      }}
    >
      <span style={{ fontWeight: 700, fontSize: '0.85rem', letterSpacing: '0.5px' }}>{label}</span>
      <span style={{ fontSize: '0.65rem', opacity: 0.85 }}>{sublabel}</span>
    </button>
  )
}

function shuffle<T>(arr: T[]): void {
  for (let i = arr.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1))
    ;[arr[i], arr[j]] = [arr[j], arr[i]]
  }
}
