import { motion, AnimatePresence } from 'framer-motion'
import { LatinToggle } from './LatinToggle'

// Flashcard mit 3D-Flip-Animation laut CLAUDE.md §6.1.
// Vorderseite: HU-Wort + Phonetik. Rückseite: DE-Wort, Latein-Toggle, Beispiel.
// Klick irgendwo auf die Card → Flip.

export type FlashcardData = {
  id: number
  hungarian: string
  phonetic: string | null
  german: string
  latin_term: string | null
  example_hu: string | null
  example_de: string | null
}

type Props = {
  card: FlashcardData
  flipped: boolean
  onFlip: () => void
}

export function Flashcard({ card, flipped, onFlip }: Props) {
  return (
    <div
      style={{
        perspective: '1200px',
        width: '100%',
        maxWidth: 380,
        aspectRatio: '3 / 4'
      }}
    >
      <motion.div
        animate={{ rotateY: flipped ? 180 : 0 }}
        transition={{ duration: 0.45, ease: [0.4, 0, 0.2, 1] }}
        style={{
          width: '100%',
          height: '100%',
          position: 'relative',
          transformStyle: 'preserve-3d',
          cursor: 'pointer'
        }}
        onClick={onFlip}
      >
        <CardFace>
          <div className="hu-vocab" style={{ color: 'var(--red)', textAlign: 'center' }}>
            {card.hungarian}
          </div>
          {card.phonetic && (
            <div
              className="phonetic"
              style={{ marginTop: '0.5rem', textAlign: 'center', fontSize: '1rem' }}
            >
              [{card.phonetic}]
            </div>
          )}
          <div
            style={{
              position: 'absolute',
              bottom: 14,
              left: 0,
              right: 0,
              textAlign: 'center',
              fontSize: '0.7rem',
              opacity: 0.5,
              letterSpacing: '0.5px'
            }}
          >
            tippen zum Umdrehen
          </div>
        </CardFace>

        <CardFace back>
          <div
            style={{
              fontFamily: 'Georgia, serif',
              fontSize: '1.6rem',
              fontWeight: 700,
              color: 'var(--green)',
              textAlign: 'center'
            }}
          >
            {card.german}
          </div>

          <AnimatePresence>
            {(card.example_hu || card.example_de) && (
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                transition={{ delay: 0.25 }}
                style={{
                  marginTop: '0.9rem',
                  padding: '0.6rem 0.85rem',
                  background: 'var(--cream)',
                  borderRadius: 10,
                  fontSize: '0.85rem',
                  textAlign: 'center',
                  width: '100%'
                }}
              >
                {card.example_hu && <div style={{ fontStyle: 'italic' }}>{card.example_hu}</div>}
                {card.example_de && <div style={{ opacity: 0.7, marginTop: 2 }}>{card.example_de}</div>}
              </motion.div>
            )}
          </AnimatePresence>

          <div style={{ marginTop: 'auto', paddingTop: '1rem' }}>
            <LatinToggle latinTerm={card.latin_term} />
          </div>
        </CardFace>
      </motion.div>
    </div>
  )
}

function CardFace({ children, back }: { children: React.ReactNode; back?: boolean }) {
  return (
    <div
      style={{
        position: 'absolute',
        inset: 0,
        background: 'var(--white)',
        border: `2px solid ${back ? 'var(--green)' : 'var(--red)'}`,
        borderRadius: 18,
        boxShadow: 'var(--shadow-card)',
        backfaceVisibility: 'hidden',
        WebkitBackfaceVisibility: 'hidden',
        transform: back ? 'rotateY(180deg)' : 'rotateY(0deg)',
        padding: '1.5rem 1.25rem',
        display: 'flex',
        flexDirection: 'column',
        alignItems: 'center',
        justifyContent: 'center',
        textAlign: 'center'
      }}
    >
      {children}
    </div>
  )
}
